INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('drug_reference', 'metformin', ARRAY['میٹفارمین','شوگر','ذیابیطس','گلوکوفاج'], 'میٹفارمین', E'## میٹفارمین\n\n**زمرہ:** Biguanide - ذیابیطس کی دوا\n\n**خوراک:** 500mg دن میں 2 بار (زیادہ سے زیادہ 2g/دن)\n\n**استعمال:** ٹائپ 2 ذیابیطس، PCOS\n\n**ضمنی اثرات:** متلی، اسہال، پیٹ درد (شروع میں عام)\n\n**⚠️ احتیاط:**\n- گردے فیل (eGFR < 30) میں منع\n- سرجری سے پہلے بند کریں\n- لیکٹک ایسڈوسس (نایاب مگر سنگین)\n- وٹامن B12 کی کمی ہو سکتی ہے', 'ur', 'BNF/ADA', 7, true),
('drug_reference', 'amlodipine', ARRAY['املوڈیپین','بلڈ پریشر','نورواسک'], 'املوڈیپین', E'## املوڈیپین\n\n**زمرہ:** کیلشیم چینل بلاکر\n\n**خوراک:** 5-10mg روزانہ ایک بار\n\n**استعمال:** ہائی بلڈ پریشر، انجائنا\n\n**ضمنی اثرات:** ٹانگوں میں سوجن، سر درد، چہرے کی سرخی\n\n**⚠️ احتیاط:**\n- شدید aortic stenosis میں محتاط\n- حمل میں منع\n- گریپ فروٹ سے پرہیز', 'ur', 'BNF/NICE', 7, true),
('drug_reference', 'losartan', ARRAY['لوسارٹن','بلڈ پریشر','ARB','کوزار'], 'لوسارٹن', E'## لوسارٹن\n\n**زمرہ:** ARB (Angiotensin Receptor Blocker)\n\n**خوراک:** 50-100mg روزانہ ایک بار\n\n**استعمال:** ہائی بلڈ پریشر، ذیابیطس گردے کی حفاظت\n\n**ضمنی اثرات:** چکر آنا، زیادہ پوٹاشیم\n\n**⚠️ احتیاط:**\n- حمل میں سختی سے منع\n- پوٹاشیم چیک کریں\n- ACE inhibitor کے ساتھ نہ دیں\n- گردے کے فنکشن ٹیسٹ باقاعدہ', 'ur', 'BNF/NICE', 7, true),
('drug_reference', 'atorvastatin', ARRAY['اٹورواسٹیٹن','کولیسٹرول','لپڈ','لپیٹر'], 'اٹورواسٹیٹن', E'## اٹورواسٹیٹن\n\n**زمرہ:** Statin\n\n**خوراک:** 10-80mg رات کو ایک بار\n\n**استعمال:** زیادہ کولیسٹرول، دل کی بیماری سے بچاؤ\n\n**ضمنی اثرات:** پٹھوں میں درد، جگر کے انزائم بڑھنا\n\n**⚠️ احتیاط:**\n- CK چیک اگر پٹھوں میں درد\n- جگر فنکشن ٹیسٹ شروع میں اور 3 ماہ بعد\n- حمل/دودھ پلانے میں منع\n- Rhabdomyolysis (نایاب مگر سنگین)', 'ur', 'BNF/NICE', 7, true),
('drug_reference', 'metoprolol', ARRAY['میٹوپرولول','دل کی دھڑکن','بیٹا بلاکر'], 'میٹوپرولول', E'## میٹوپرولول\n\n**زمرہ:** Beta-blocker\n\n**خوراک:** 25-100mg دن میں 2 بار\n\n**استعمال:** ہائی BP، انجائنا، دل کی بے ترتیب دھڑکن، دل کا دورے کے بعد\n\n**ضمنی اثرات:** تھکاوٹ، سست دھڑکن، ٹھنڈے ہاتھ پاؤں\n\n**⚠️ احتیاط:**\n- دمہ میں منع\n- اچانک بند نہ کریں\n- ذیابیطس میں شوگر کم ہونے کی علامات چھپ سکتی ہیں', 'ur', 'BNF', 7, true),
('drug_reference', 'salbutamol', ARRAY['سالبوٹامول','بخاخ','دمہ','وینٹولین'], 'سالبوٹامول انہیلر', E'## سالبوٹامول انہیلر\n\n**زمرہ:** Short-acting beta-agonist (SABA)\n\n**خوراک:** 2 پف ضرورت کے مطابق (زیادہ سے زیادہ 8 پف/دن)\n\n**استعمال:** دمہ، COPD میں فوری راحت\n\n**ضمنی اثرات:** کانپنا، تیز دھڑکن، سر درد\n\n**⚠️ اہم:**\n- ہفتے میں 3 بار سے زیادہ استعمال = دمہ قابو میں نہیں\n- Spacer استعمال کریں بہتر اثر کے لیے\n- شدید حملے میں: 10 پف ہر 20 منٹ', 'ur', 'BTS/GINA', 7, true),
('drug_reference', 'prednisolone', ARRAY['پریڈنیزولون','سٹیرائڈ','کورٹیزون','سوزش'], 'پریڈنیزولون', E'## پریڈنیزولون\n\n**زمرہ:** Corticosteroid\n\n**خوراک:** حالت کے مطابق مختلف\n- دمہ حملہ: 40mg × 5 دن\n- COPD: 30mg × 5 دن\n\n**استعمال:** سوزش، الرجی، دمہ، آٹو امیون\n\n**ضمنی اثرات:** شوگر بڑھنا، بھوک زیادہ، نیند خرابی، موڈ تبدیلی\n\n**⚠️ احتیاط:**\n- 3 ہفتے سے زیادہ: آہستہ آہستہ کم کریں\n- PPI ساتھ دیں (پیٹ کی حفاظت)\n- لمبے عرصے: ہڈیوں، شوگر، آنکھوں کی جانچ', 'ur', 'BNF', 7, true),
('drug_reference', 'amoxicillin', ARRAY['اموکسیسیلین','اینٹی بائیوٹک','انفیکشن'], 'اموکسیسیلین', E'## اموکسیسیلین\n\n**زمرہ:** Penicillin اینٹی بائیوٹک\n\n**خوراک:** 500mg دن میں 3 بار × 5-7 دن\n\n**استعمال:** کان، گلا، سانس، پیشاب کے انفیکشن\n\n**ضمنی اثرات:** اسہال، متلی، ددورے (الرجی)\n\n**⚠️ احتیاط:**\n- Penicillin الرجی میں سختی سے منع\n- Glandular fever میں ددورے ہوتے ہیں\n- پورا کورس مکمل کریں', 'ur', 'BNF/WHO', 7, true),
('drug_reference', 'azithromycin', ARRAY['ازیتھرومائسین','زیتھروماکس','اینٹی بائیوٹک'], 'ازیتھرومائسین', E'## ازیتھرومائسین\n\n**زمرہ:** Macrolide اینٹی بائیوٹک\n\n**خوراک:** 500mg پہلے دن، پھر 250mg × 4 دن\n\n**استعمال:** سانس کے انفیکشن، جنسی انفیکشن، جلد\n\n**ضمنی اثرات:** متلی، اسہال، پیٹ درد\n\n**⚠️ احتیاط:**\n- QT prolongation کا خطرہ\n- جگر کی بیماری میں محتاط\n- Penicillin الرجی والوں کے لیے متبادل', 'ur', 'BNF/WHO', 7, true),
('drug_reference', 'ciprofloxacin', ARRAY['سیپروفلوکساسین','فلوروکوینولون','پیشاب انفیکشن'], 'سیپروفلوکساسین', E'## سیپروفلوکساسین\n\n**زمرہ:** Fluoroquinolone\n\n**خوراک:** 500mg دن میں 2 بار × 7 دن\n\n**استعمال:** پیشاب انفیکشن، پیٹ کے انفیکشن، ہڈی\n\n**ضمنی اثرات:** متلی، اسہال، سر درد\n\n**⚠️ سنگین احتیاط:**\n- نسوں کو نقصان (Achilles tendon rupture)\n- بچوں میں منع (جوڑوں پر اثر)\n- حمل میں منع\n- Aortic dissection کا خطرہ بزرگوں میں\n- دودھ، کیلشیم سے دور رکھیں', 'ur', 'BNF/FDA', 7, true),
('drug_reference', 'metronidazole', ARRAY['میٹرونیڈازول','فلیجل','انفیکشن','اینیروبک'], 'میٹرونیڈازول', E'## میٹرونیڈازول\n\n**زمرہ:** Nitroimidazole اینٹی بائیوٹک\n\n**خوراک:** 400mg دن میں 3 بار × 7 دن\n\n**استعمال:** پیٹ کے انفیکشن، اندام نہانی انفیکشن، دانتوں کا انفیکشن، C. diff\n\n**ضمنی اثرات:** منہ میں دھاتی ذائقہ، متلی\n\n**⚠️ احتیاط:**\n- شراب سے سختی سے پرہیز (شدید الٹی)\n- علاج کے بعد 48 گھنٹے تک شراب نہیں\n- طویل استعمال سے اعصابی نقصان', 'ur', 'BNF', 7, true),
('drug_reference', 'fluoxetine', ARRAY['فلوکسیٹین','پروزاک','ڈپریشن','اینٹی ڈپریسنٹ'], 'فلوکسیٹین', E'## فلوکسیٹین\n\n**زمرہ:** SSRI اینٹی ڈپریسنٹ\n\n**خوراک:** 20mg صبح (زیادہ سے زیادہ 60mg)\n\n**استعمال:** ڈپریشن، OCD، بلیمیا\n\n**ضمنی اثرات:** متلی، سر درد، بے چینی (شروع میں)\n\n**⚠️ احتیاط:**\n- اثر 4-6 ہفتوں میں شروع ہوتا ہے\n- اچانک بند نہ کریں\n- نوجوانوں میں خودکشی کے خیالات کی نگرانی\n- بہتری کے بعد 6 ماہ جاری رکھیں', 'ur', 'BNF/NICE', 7, true),
('drug_reference', 'diazepam', ARRAY['ڈائزیپام','ویلیم','بے چینی','دورے','نیند'], 'ڈائزیپام', E'## ڈائزیپام\n\n**زمرہ:** Benzodiazepine\n\n**خوراک:** 2-10mg ضرورت کے مطابق\n\n**استعمال:** شدید بے چینی، پٹھوں کی اکڑن، دورے، نشے کی واپسی\n\n**ضمنی اثرات:** غنودگی، الجھن، لت\n\n**⚠️ سنگین احتیاط:**\n- 2-4 ہفتے سے زیادہ نہ دیں (لت لگتی ہے)\n- بزرگوں میں آدھی خوراک\n- سانس کی بیماری میں محتاط\n- شراب کے ساتھ سختی سے منع\n- ڈرائیونگ سے پرہیز', 'ur', 'BNF', 7, true),
('drug_reference', 'insulin_rapid', ARRAY['انسولین','تیز انسولین','NovoRapid','شوگر'], 'تیز اثر انسولین', E'## تیز اثر انسولین (Rapid-acting)\n\n**اقسام:** Aspart (NovoRapid)، Lispro (Humalog)\n\n**شروع:** 10-15 منٹ\n**عروج:** 1-2 گھنٹے\n**مدت:** 3-5 گھنٹے\n\n**استعمال:** کھانے سے پہلے، شوگر درست کرنے کے لیے\n\n**⚠️ احتیاط:**\n- ہائپوگلائسیمیا کی علامات سکھائیں\n- انجکشن کی جگہ بدلتے رہیں\n- فریج میں رکھیں (استعمال میں: کمرے کے درجہ حرارت × 28 دن)', 'ur', 'ADA/BNF', 7, true),
('drug_reference', 'insulin_long', ARRAY['انسولین','طویل انسولین','لینٹس','گلارجین'], 'طویل اثر انسولین', E'## طویل اثر انسولین (Long-acting)\n\n**اقسام:** Glargine (Lantus)، Detemir (Levemir)\n\n**شروع:** 1-2 گھنٹے\n**مدت:** 18-24+ گھنٹے\n\n**خوراک:** روزانہ ایک بار (عام طور پر رات کو)\n\n**⚠️ احتیاط:**\n- کبھی IV نہ دیں\n- کبھی ملائیں نہیں\n- رات کی ہائپوگلائسیمیا کا خطرہ\n- خوراک آہستہ آہستہ بڑھائیں', 'ur', 'ADA/BNF', 7, true),
('drug_reference', 'warfarin', ARRAY['وارفرین','خون پتلا','INR','جمنے روکنا'], 'وارفرین', E'## وارفرین\n\n**زمرہ:** Anticoagulant (خون پتلا کرنے والی)\n\n**خوراک:** INR کے مطابق ایڈجسٹ (عام ہدف 2-3)\n\n**استعمال:** DVT/PE، AF، مصنوعی والو\n\n**⚠️ سنگین احتیاط:**\n- INR باقاعدہ چیک کریں\n- بہت سی دوائیوں اور خوراک سے تعامل\n- وٹامن K والی سبزیاں مستقل مقدار میں\n- خون بہنے کا خطرہ\n- حمل میں سختی سے منع\n\n**INR > 8:** وٹامن K 1-5mg + وارفرین بند', 'ur', 'BNF/NICE', 7, true),
('drug_reference', 'aspirin', ARRAY['ایسپرین','دل','خون پتلا','درد'], 'ایسپرین', E'## ایسپرین\n\n**زمرہ:** Antiplatelet / NSAID\n\n**خوراک:**\n- دل کی حفاظت: 75mg روزانہ\n- دل کے دورے میں: 300mg چبائیں\n\n**استعمال:** دل کا دورہ، اسٹروک سے بچاؤ، درد\n\n**ضمنی اثرات:** پیٹ درد، خون بہنا، معدے کا السر\n\n**⚠️ احتیاط:**\n- 16 سال سے کم عمر میں منع (Reye syndrome)\n- پیٹ کے السر میں منع\n- PPI ساتھ دینے پر غور', 'ur', 'BNF/AHA', 7, true),
('drug_reference', 'diclofenac', ARRAY['ڈکلوفیناک','وولٹارین','درد','سوزش'], 'ڈکلوفیناک', E'## ڈکلوفیناک\n\n**زمرہ:** NSAID\n\n**خوراک:** 50mg دن میں 3 بار (زیادہ سے زیادہ 150mg/دن)\n\n**استعمال:** درد، سوزش، گردے کی پتھری کا درد\n\n**⚠️ سنگین احتیاط:**\n- دل کی بیماری میں خطرناک\n- معدے کا السر/خون بہنا\n- گردے خراب کر سکتی ہے\n- کم ترین خوراک کم ترین وقت کے لیے\n- PPI ساتھ دیں اگر ضروری ہو', 'ur', 'BNF/FDA', 7, true),
('drug_reference', 'tramadol', ARRAY['ٹرامادول','درد','اوپیائڈ','شدید درد'], 'ٹرامادول', E'## ٹرامادول\n\n**زمرہ:** Opioid درد کش\n\n**خوراک:** 50-100mg ہر 4-6 گھنٹے (زیادہ سے زیادہ 400mg/دن)\n\n**استعمال:** اعتدال سے شدید درد\n\n**ضمنی اثرات:** متلی، چکر، قبض، غنودگی\n\n**⚠️ سنگین احتیاط:**\n- لت لگ سکتی ہے\n- دورے کا خطرہ (خاص طور پر SSRIs کے ساتھ)\n- سانس دبنے کا خطرہ\n- بزرگوں میں کم خوراک\n- ڈرائیونگ سے پرہیز', 'ur', 'BNF', 7, true),
('drug_reference', 'doxycycline', ARRAY['ڈوکسی سائکلین','اینٹی بائیوٹک','ٹیٹراسائکلین'], 'ڈوکسی سائکلین', E'## ڈوکسی سائکلین\n\n**زمرہ:** Tetracycline اینٹی بائیوٹک\n\n**خوراک:** 100mg دن میں 2 بار\n\n**استعمال:** سانس انفیکشن، کیل مہاسے، ملیریا (بچاؤ)، کلیمائڈیا\n\n**ضمنی اثرات:** دھوپ سے حساسیت، متلی، غذائی نالی کی سوزش\n\n**⚠️ احتیاط:**\n- حاملہ اور 8 سال سے کم عمر بچوں میں منع\n- کافی پانی کے ساتھ لیں\n- دودھ اور اینٹی ایسڈ سے دور رکھیں', 'ur', 'BNF', 7, true),
('drug_reference', 'omeprazole', ARRAY['اومیپرازول','پیٹ','ایسیڈ','معدے کا السر'], 'اومیپرازول', E'## اومیپرازول\n\n**زمرہ:** Proton Pump Inhibitor (PPI)\n\n**خوراک:** 20-40mg روزانہ ایک بار (کھانے سے پہلے)\n\n**استعمال:** معدے کا السر، ایسیڈ ریفلکس، NSAID سے بچاؤ\n\n**ضمنی اثرات:** سر درد، پیٹ درد، اسہال\n\n**⚠️ احتیاط:**\n- طویل استعمال: میگنیشیم کمی، ہڈیوں کا نقصان، C. diff\n- 8 ہفتے سے زیادہ: ضرورت کا جائزہ لیں\n- Clopidogrel کے ساتھ تعامل', 'ur', 'BNF/NICE', 7, true),
('drug_reference', 'ferrous_sulfate', ARRAY['آئرن','حدید','فیرس سلفیٹ','خون کی کمی'], 'فیرس سلفیٹ (آئرن)', E'## فیرس سلفیٹ\n\n**زمرہ:** آئرن سپلیمنٹ\n\n**خوراک:** 200mg دن میں 2-3 بار (خالی پیٹ بہتر)\n\n**استعمال:** آئرن کی کمی سے خون کی کمی\n\n**ضمنی اثرات:** قبض، متلی، پاخانہ سیاہ\n\n**⚠️ احتیاط:**\n- وٹامن C ساتھ لیں (جذب بہتر)\n- چائے/دودھ سے 2 گھنٹے دور\n- 3 ماہ تک جاری رکھیں\n- بچوں سے دور رکھیں (زہریلا)', 'ur', 'BNF/WHO', 7, true),
('drug_reference', 'folic_acid', ARRAY['فولک ایسڈ','حمل','وٹامن','خون کی کمی'], 'فولک ایسڈ', E'## فولک ایسڈ\n\n**خوراک:**\n- حمل: 400mcg روزانہ (حمل سے پہلے شروع)\n- زیادہ خطرہ: 5mg روزانہ\n- خون کی کمی: 5mg روزانہ\n\n**استعمال:** حمل میں دماغی/ریڑھ کی خرابی سے بچاؤ، فولیٹ کی کمی\n\n**⚠️ احتیاط:**\n- B12 کی کمی خارج کریں پہلے\n- Methotrexate کے ساتھ: ڈاکٹر کی ہدایت پر\n- حمل سے 3 ماہ پہلے شروع کریں', 'ur', 'BNF/WHO', 7, true),
('drug_reference', 'vitamin_d', ARRAY['وٹامن ڈی','ہڈیاں','کیلشیم','دھوپ'], 'وٹامن ڈی', E'## وٹامن ڈی\n\n**خوراک:**\n- بچاؤ: 400-1000 IU روزانہ\n- کمی کا علاج: 50,000 IU ہفتہ وار × 8 ہفتے\n\n**استعمال:** وٹامن ڈی کی کمی، ہڈیوں کی کمزوری\n\n**ضمنی اثرات:** بہت زیادہ سے: کیلشیم بڑھنا، گردے کی پتھری\n\n**⚠️ احتیاط:**\n- سطح چیک کریں علاج سے پہلے\n- کیلشیم ساتھ دینے پر غور\n- گردے کی بیماری میں active form دیں', 'ur', 'BNF/Endocrine Society', 7, true),
('drug_reference', 'calcium', ARRAY['کیلشیم','ہڈیاں','آسٹیوپوروسس'], 'کیلشیم', E'## کیلشیم سپلیمنٹ\n\n**خوراک:** 500-1000mg روزانہ\n\n**استعمال:** ہڈیوں کی کمزوری، وٹامن ڈی کے ساتھ\n\n**ضمنی اثرات:** قبض، پیٹ پھولنا\n\n**⚠️ احتیاط:**\n- آئرن سے 2 گھنٹے دور\n- تھائرائڈ دوا سے 4 گھنٹے دور\n- زیادہ سے گردے کی پتھری\n- کھانے کے ساتھ بہتر جذب ہوتا ہے', 'ur', 'BNF', 7, true),
('drug_reference', 'montelukast', ARRAY['مونٹیلوکاسٹ','دمہ','الرجی','سنگولیئر'], 'مونٹیلوکاسٹ', E'## مونٹیلوکاسٹ\n\n**زمرہ:** Leukotriene receptor antagonist\n\n**خوراک:** 10mg رات کو (بالغ)، 4-5mg بچے\n\n**استعمال:** دمہ (اضافی علاج)، الرجی ناک\n\n**ضمنی اثرات:** سر درد، پیٹ درد\n\n**⚠️ احتیاط:**\n- نفسیاتی ضمنی اثرات (ڈپریشن، بے چینی، خود کو نقصان)\n- FDA Black Box Warning\n- موڈ میں تبدیلی فوری رپورٹ کریں', 'ur', 'BNF/FDA', 7, true),
('drug_reference', 'chlorpheniramine', ARRAY['کلورفینیرامین','الرجی','اینٹی ہسٹامین','حساسیت'], 'کلورفینیرامین', E'## کلورفینیرامین\n\n**زمرہ:** First-gen اینٹی ہسٹامین\n\n**خوراک:** 4mg ہر 4-6 گھنٹے (زیادہ سے زیادہ 24mg/دن)\n\n**استعمال:** الرجی، چھپاکی، ناک بہنا، چھینکیں\n\n**ضمنی اثرات:** غنودگی، منہ خشک\n\n**⚠️ احتیاط:**\n- ڈرائیونگ سے پرہیز\n- بزرگوں میں الجھن کا خطرہ\n- پروسٹیٹ بڑھنے میں محتاط\n- Cetirizine/Loratadine کم نیند لانے والے متبادل ہیں', 'ur', 'BNF', 7, true),
('drug_reference', 'domperidone', ARRAY['ڈومپیریڈون','متلی','الٹی','معدہ'], 'ڈومپیریڈون', E'## ڈومپیریڈون\n\n**زمرہ:** Antiemetic / Prokinetic\n\n**خوراک:** 10mg دن میں 3 بار (کھانے سے پہلے)\n\n**استعمال:** متلی، الٹی، معدے کی سستی\n\n**ضمنی اثرات:** سر درد، خشک منہ\n\n**⚠️ احتیاط:**\n- دل کی تال خراب کر سکتی ہے (QT prolongation)\n- کم ترین خوراک کم ترین وقت\n- جگر کی بیماری میں منع\n- Metoclopramide سے بہتر (BBB عبور نہیں کرتی)', 'ur', 'BNF/EMA', 7, true),
('drug_reference', 'hyoscine', ARRAY['ہائیوسین','پیٹ مروڑ','بسکوپان','اینٹی سپازم'], 'ہائیوسین بیوٹائل بروماید', E'## ہائیوسین بیوٹائل بروماید (Buscopan)\n\n**زمرہ:** Antispasmodic\n\n**خوراک:** 20mg دن میں 4 بار\n\n**استعمال:** پیٹ مروڑ، IBS، ماہواری کے درد، گردے/پتے کا درد\n\n**ضمنی اثرات:** خشک منہ، دھندلی نظر، قبض\n\n**⚠️ احتیاط:**\n- گلوکوما میں منع\n- پروسٹیٹ بڑھنے میں محتاط\n- بزرگوں میں محتاط استعمال', 'ur', 'BNF', 7, true),
('drug_reference', 'ors', ARRAY['ORS','نمکول','اسہال','پانی کی کمی'], 'ORS (نمکول)', E'## ORS نمکول\n\n**ترکیب:** سوڈیم، پوٹاشیم، گلوکوز، سائٹریٹ\n\n**تیاری:** ایک پیکٹ ایک لیٹر صاف پانی میں\n\n**خوراک:**\n- 2 سال سے کم: 50-100mL ہر اسہال کے بعد\n- 2-10 سال: 100-200mL\n- بڑے: ضرورت کے مطابق\n\n**⚠️ اہم:**\n- 24 گھنٹے بعد پھینک دیں\n- شدید پانی کی کمی: آنکھیں دھنسی، جلد ڈھیلی، پیشاب بہت کم → فوری ہسپتال', 'ur', 'WHO', 7, true),
('drug_reference', 'loperamide', ARRAY['لوپیرامائڈ','اسہال','اموڈیم'], 'لوپیرامائڈ', E'## لوپیرامائڈ\n\n**زمرہ:** اسہال روکنے والی دوا\n\n**خوراک:** 4mg پہلے، پھر 2mg ہر اسہال بعد (زیادہ سے زیادہ 16mg/دن)\n\n**استعمال:** شدید غیر متعدی اسہال\n\n**⚠️ احتیاط:**\n- خونی اسہال یا بخار میں استعمال نہ کریں\n- 2 سال سے کم عمر میں منع\n- 48 گھنٹے میں بہتری نہ ہو تو بند کریں\n- C. diff اسہال میں منع', 'ur', 'BNF', 7, true),
('drug_reference', 'paracetamol', ARRAY['پیراسیٹامول','پینادول','بخار','درد'], 'پیراسیٹامول', E'## پیراسیٹامول\n\n**زمرہ:** درد کش / بخار اتارنے والی\n\n**خوراک:** 500-1000mg ہر 4-6 گھنٹے (زیادہ سے زیادہ 4g/دن)\n\n**استعمال:** ہلکا سے اعتدال پسند درد، بخار\n\n**⚠️ سنگین احتیاط:**\n- زیادہ مقدار جگر تباہ کرتی ہے (150mg/kg سے زیادہ)\n- شراب پینے والوں میں کم خوراک\n- جگر کی بیماری میں محتاط\n- بہت سی دوائیوں میں پہلے سے شامل ہوتی ہے - دوہری خوراک سے بچیں\n\n**زیادہ مقدار:** N-acetylcysteine فوری', 'ur', 'BNF/WHO', 7, true);
